import{_ as r,I as e,o as s,c as i,at as l,J as o}from"./chunks/framework.DYZFTu11.js";const _=JSON.parse('{"title":"欧加斯财团 (Ogas Syndicate)","description":"","frontmatter":{},"headers":[],"relativePath":"zh_cn/organizations/the-ogas-consortium.md","filePath":"zh_cn/organizations/the-ogas-consortium.md","lastUpdated":1773492427000}'),h={name:"zh_cn/organizations/the-ogas-consortium.md"};function c(d,a,g,p,u,b){const t=e("NolebaseGitContributors"),n=e("NolebaseGitChangelog");return s(),i("div",null,[a[0]||(a[0]=l('<h1 id="欧加斯财团-ogas-syndicate" tabindex="-1">欧加斯财团 (Ogas Syndicate) <a class="header-anchor" href="#欧加斯财团-ogas-syndicate" aria-label="Permalink to “欧加斯财团 (Ogas Syndicate)”">​</a></h1><blockquote><p><strong>&quot;影子帝国，资本的主宰者&quot;</strong></p></blockquote><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p><strong>欧加斯财团</strong>（The Ogas Syndicate）是一个拥抱巨型企业主义（Mega-Corporation）的庞然大物。表面上，它是一家经营金融、科技、军工和生物医药的跨国巨型企业联合体，为人类社会提供着不可或缺的基础服务与尖端产品。</p><p>然而，在光鲜亮丽的财报与慈善晚宴背后，实际上，它通过无孔不入的经济渗透、深层的政治操控以及强大的私人军事威慑，在幕后牢牢控制着整个人类政府。</p><p>它没有公开的国旗或领土，却掌握着比许多主权国家更强大的权力。其触角延伸至社会的每一个角落，下属拥有多个子公司，分别扼守并控制着人类文明的各个命脉。</p><h2 id="核心信条" tabindex="-1">核心信条 <a class="header-anchor" href="#核心信条" aria-label="Permalink to “核心信条”">​</a></h2><blockquote><p><strong>&quot;资本即权力，控制即统治。&quot;</strong></p></blockquote><p>在欧加斯财团的运作逻辑中，利润不仅是目的，更是通向绝对权力的手段。他们相信，通过完美的控制论与经济模型，人类社会可以像精密的机器一样高效运转——只要这台机器的控制权掌握在他们手中。</p><hr><h2 id="与其他组织的关系" tabindex="-1">与其他组织的关系 <a class="header-anchor" href="#与其他组织的关系" aria-label="Permalink to “与其他组织的关系”">​</a></h2><h3 id="🏛️-人类政府-human-government" tabindex="-1">🏛️ 人类政府 (Human Government) <a class="header-anchor" href="#🏛️-人类政府-human-government" aria-label="Permalink to “🏛️ 人类政府 (Human Government)”">​</a></h3><p><strong>关系状态：</strong> [💙💙💙💙💙💙💙💙💙💙] (深度控制 / 傀儡) 欧加斯财团是人类政府背后的真正主宰。政府的决策往往需要经过财团董事会的“风险评估”，而法律的制定也常常带有财团游说的影子。在财团眼中，政府不过是管理民众的行政外壳。</p><h3 id="🏢-下属公司-subsidiary-companies" tabindex="-1">🏢 下属公司 (Subsidiary Companies) <a class="header-anchor" href="#🏢-下属公司-subsidiary-companies" aria-label="Permalink to “🏢 下属公司 (Subsidiary Companies)”">​</a></h3><p><strong>关系状态：</strong> [💛💛💛💛💛💛💛🤍🤍🤍] (高度服从 / 利益共同体) 虽然内部存在激烈的绩效竞争和派系斗争，但所有子公司在面对外部威胁或集团利益时，都会表现出绝对的忠诚与高效的执行力。它们是财团意志的延伸。</p><h3 id="🔮-灵裔-spirit-descendants" tabindex="-1">🔮 灵裔 (Spirit Descendants) <a class="header-anchor" href="#🔮-灵裔-spirit-descendants" aria-label="Permalink to “🔮 灵裔 (Spirit Descendants)”">​</a></h3><p><strong>关系状态：</strong> [💙🤍🤍🤍🤍🤍🤍🤍🤍🤍] (剥削 / 潜在叛乱) 灵裔被财团视为一种宝贵的“资源”或“工具”，而非平等的智慧生命。财团利用合同和技术手段限制他们的自由，压榨其价值。</p><blockquote><p><strong>灵裔评价：</strong> &quot;他们给我们戴上镣铐，却忘了——镣铐也能勒断他们的脖子。&quot;</p></blockquote><h3 id="⚔️-反抗组织-黎明之剑-dawn-sword" tabindex="-1">⚔️ 反抗组织 - “黎明之剑” (Dawn Sword) <a class="header-anchor" href="#⚔️-反抗组织-黎明之剑-dawn-sword" aria-label="Permalink to “⚔️ 反抗组织 - “黎明之剑” (Dawn Sword)”">​</a></h3><p><strong>关系状态：</strong> [💛🤍🤍🤍🤍🤍🤍🤍🤍🤍] (敌对 / 武装冲突) “黎明之剑”是财团秩序最大的破坏者，双方经常在暗处发生激烈的武装冲突。财团视其为必须要清除的“不稳定因素”。</p><blockquote><p><strong>“黎明之剑”评价：</strong> &quot;欧加斯财团的钱买不到我们的命，但我们的子弹能买它们的坟！&quot;</p></blockquote><h3 id="🚶-归家者-the-returners" tabindex="-1">🚶 &quot;归家者&quot; (The Returners) <a class="header-anchor" href="#🚶-归家者-the-returners" aria-label="Permalink to “🚶 &quot;归家者&quot; (The Returners)”">​</a></h3><p><strong>关系状态：</strong> [🤍🤍🤍🤍🤍🤍🤍🤍🤍🤍] (拒绝 / 无法收买) 对于试图超脱于现有体制之外的“归家者”，财团的常规手段（金钱、契约、法律陷阱）往往失效。财团极其厌恶这种无法被“定价”和“量化”的存在。</p><blockquote><p><strong>“归家者”彩莉评价：</strong> &quot;——你们的那些用合同、债务和算法武装的<strong>吞人机器</strong>配不上我。&quot;</p></blockquote><hr><h2 id="势力范围与手段-拓展资料" tabindex="-1">势力范围与手段 (拓展资料) <a class="header-anchor" href="#势力范围与手段-拓展资料" aria-label="Permalink to “势力范围与手段 (拓展资料)”">​</a></h2><p>为了维持其庞大的商业帝国，欧加斯财团在各个关键领域都拥有绝对的话语权：</p><ul><li><strong>金融垄断 (Financial Dominance)</strong>：通过控制全球通用的信用货币体系，财团可以轻易地对敌对势力并在经济上进行“降维打击”，或通过债务陷阱控制新兴城市。</li><li><strong>尖端科技 (High-Tech)</strong>：掌握着最先进的人工智能、网络安全及量子计算技术。这不仅用于商业，更用于监控和舆论引导。</li><li><strong>军事工业 (Military Industry)</strong>：拥有独立于政府军之外的私人安保部队（PMC），装备着最精良的单兵外骨骼与无人机群，名为“资产保护”，实为武力威慑。</li><li><strong>生物医药 (Bio-Medicine)</strong>：垄断了高端医疗资源和基因强化技术。对平民而言，健康是需要购买的昂贵服务；对高层而言，这是延续统治寿命的保障。</li></ul>',28)),o(t),o(n)])}const q=r(h,[["render",c]]);export{_ as __pageData,q as default};
